// Compliant: Remove redundant self-assignments
func updateUser(user User) User {
    // Only update what actually changes
    user.UpdatedAt = time.Now()

    return user
}

// Compliant: Proper item processing
func processItems(items []Item) {
    for i, item := range items {
        if item.IsValid() {
            // Process and update the item
            processedItem := processItem(item)
            items[i] = processedItem
        }
    }
}

// Compliant: Correct struct field updates
func mergeUserData(existing User, updates User) User {
    if updates.Name != "" {
        existing.Name = updates.Name
    }
    if updates.Email != "" {
        existing.Email = updates.Email // Fixed: assign from updates
    }
    if updates.Phone != "" {
        existing.Phone = updates.Phone
    }

    return existing
}

// Compliant: Proper variable swapping
func swap(a, b *int) {
    *a, *b = *b, *a // Go's multiple assignment for swapping
}

// Alternative swapping with temporary variable
func swapWithTemp(a, b *int) {
    temp := *a
    *a = *b
    *b = temp
}

// Compliant: Meaningful data transformations
func validateAndUpdate(user *User) error {
    if user.Name == "" {
        return errors.New("name is required")
    }

    // Properly normalize email
    if user.Email != "" {
        user.Email = strings.ToLower(user.Email)
        user.Email = strings.TrimSpace(user.Email)
    }

    return nil
}

// Compliant: Clear error handling
func parseConfig(data []byte) (Config, error) {
    var config Config

    err := json.Unmarshal(data, &config)
    if err != nil {
        return Config{}, fmt.Errorf("config parsing failed: %w", err)
    }

    return config, nil
}

// Compliant: When you need to explicitly maintain a value
func sanitizeUserInput(user *User) {
    // Sanitize name but preserve original in audit field
    originalName := user.Name
    user.Name = strings.TrimSpace(user.Name)
    user.Name = strings.Title(user.Name)

    // Keep audit trail of changes
    if user.Name != originalName {
        user.AuditLog = append(user.AuditLog, fmt.Sprintf("Name changed from '%s' to '%s'", originalName, user.Name))
    }
}

// Compliant: Defensive copying when needed
func processUserSafely(user User) User {
    // Create a copy to avoid modifying the original
    userCopy := user
    userCopy.ProcessedAt = time.Now()
    userCopy.Status = "processed"

    return userCopy
}

// Compliant: Builder pattern avoiding self-assignment
type UserBuilder struct {
    user User
}

func NewUserBuilder() *UserBuilder {
    return &UserBuilder{user: User{}}
